1	//! Chromium process lifecycle management.
2	//!
3	//! Spawns headless Chromium with `--remote-debugging-port`, monitors
4	//! its health, and guarantees cleanup on drop.
5	//!
6	//! # Safety invariant
7	//!
8	//! When [`ChromiumProcess`] is dropped, the child process MUST be killed.
9	//! Zombie Chromium processes are a hard bug.
10	
11	use std::net::TcpListener;
12	use std::path::PathBuf;
13	use std::time::Duration;
14	
15	use ans_stealth::StealthConfig;
16	use tokio::process::{Child, Command};
17	use tracing;
18	
19	/// Owns a running Chromium child process.
20	///
21	/// Created via [`ChromiumProcess::launch`]. On drop, the child is killed
22	/// and the temporary user-data directory is removed.
23	pub struct ChromiumProcess {
24	    child: Option<Child>,
25	    debug_port: u16,
26	    debug_url: String,
27	    /// WebSocket URL for the first page target (not the browser endpoint).
28	    page_url: String,
29	    user_data_dir: PathBuf,
30	}
31	
32	impl ChromiumProcess {
33	    /// Launch a headless Chromium instance with remote debugging enabled.
34	    ///
35	    /// Finds the Chromium executable on PATH (or common install locations),
36	    /// allocates an ephemeral port, spawns the process, and waits for the
37	    /// debug WebSocket URL to become available.
38	    ///
39	    /// When `stealth` is provided, anti-detection flags are merged into
40	    /// the launch command.
41	    pub async fn launch(stealth: Option<&StealthConfig>) -> Result<Self, LaunchError> {
42	        let exe = find_or_download_chromium().await?;
43	        let port = allocate_port()?;
44	        let user_data_dir =
45	            std::env::temp_dir().join(format!("ans-chromium-{}", uuid::Uuid::new_v4()));
46	
47	        std::fs::create_dir_all(&user_data_dir)?;
48	
49	        tracing::info!(
50	            exe = %exe.display(),
51	            port = port,
52	            user_data_dir = %user_data_dir.display(),
53	            stealth = stealth.is_some(),
54	            "Launching Chromium"
55	        );
56	
57	        let mut cmd = Command::new(&exe);
58	        cmd.arg("--headless=new")
59	            .arg(format!("--remote-debugging-port={port}"))
60	            .arg(format!("--user-data-dir={}", user_data_dir.display()))
61	            .arg("--no-sandbox")
62	            .arg("--disable-gpu")
63	            .arg("--disable-dev-shm-usage")
64	            .arg("--disable-extensions")
65	            .arg("--disable-background-networking")
66	            .arg("--disable-sync")
67	            .arg("--disable-translate")
68	            .arg("--disable-default-apps")
69	            .arg("--hide-scrollbars")
70	            .arg("--metrics-recording-only")
71	            .arg("--mute-audio")
72	            .arg("--no-first-run")
73	            .arg("--window-size=1280,720")
74	            .arg("--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/131.0.6778.204 Safari/537.36")
75	            .arg("about:blank");
76	
77	        // Merge stealth anti-detection flags
78	        if let Some(config) = stealth {
79	            for flag in config.chrome_flags() {
80	                cmd.arg(flag);
81	            }
82	        }
83	
84	        let child = cmd
85	            .kill_on_drop(true)
86	            .spawn()
87	            .map_err(|e| LaunchError::SpawnFailed {
88	                exe: exe.clone(),
89	                source: e,
90	            })?;
91	
92	        let debug_url = discover_debug_url(port).await?;
93	        let page_url = discover_page_url(port).await?;
94	
95	        tracing::info!(%debug_url, %page_url, "Chromium ready");
96	
97	        Ok(Self {
98	            child: Some(child),
99	            debug_port: port,
100	            debug_url,
101	            page_url,
102	            user_data_dir,
103	        })
104	    }
105	
106	    /// The browser-level WebSocket URL (for Target.* commands only).
107	    #[must_use] 
108	    pub fn debug_url(&self) -> &str {
109	        &self.debug_url
110	    }
111	
112	    /// The page-level WebSocket URL (for Page.*, DOM.*, Runtime.* commands).
113	    #[must_use] 
114	    pub fn page_url(&self) -> &str {
115	        &self.page_url
116	    }
117	
118	    /// The TCP port Chromium is listening on for CDP connections.
119	    #[must_use] 
120	    pub const fn debug_port(&self) -> u16 {
121	        self.debug_port
122	    }
123	}
124	
125	impl Drop for ChromiumProcess {
126	    fn drop(&mut self) {
127	        if let Some(mut child) = self.child.take() {
128	            tracing::debug!(pid = child.id(), "Killing Chromium child process");
129	            // kill_on_drop(true) handles this, but explicitly kill for clarity
130	            if let Err(e) = child.start_kill() {
131	                tracing::warn!(pid = child.id(), ?e, "Failed to kill Chromium process");
132	            }
133	        }
134	        if self.user_data_dir.exists() {
135	            if let Err(e) = std::fs::remove_dir_all(&self.user_data_dir) {
136	                tracing::warn!(dir = %self.user_data_dir.display(), ?e, "Failed to remove temp user-data dir");
137	            }
138	        }
139	    }
140	}
141	
142	// ── Helpers ──────────────────────────────────────────────────────────
143	
144	/// Allocate an ephemeral TCP port by binding to port 0 and reading the assigned port.
145	fn allocate_port() -> Result<u16, LaunchError> {
146	    let listener = TcpListener::bind("127.0.0.1:0")?;
147	    let port = listener.local_addr()?.port();
148	    drop(listener);
149	    Ok(port)
150	}
151	
152	/// Discover the CDP WebSocket debug URL by polling Chromium's HTTP endpoint.
153	async fn discover_debug_url(port: u16) -> Result<String, LaunchError> {
154	    let url = format!("http://127.0.0.1:{port}/json/version");
155	    let client = reqwest::Client::new();
156	
157	    // Chromium takes a moment to start. Retry with backoff.
158	    let mut attempts = 0;
159	    loop {
160	        match client
161	            .get(&url)
162	            .timeout(Duration::from_secs(5))
163	            .send()
164	            .await
165	        {
166	            Ok(resp) => {
167	                if resp.status().is_success() {
168	                    let json: serde_json::Value = resp.json().await?;
169	                    return json["webSocketDebuggerUrl"]
170	                        .as_str()
171	                        .map(String::from)
172	                        .ok_or(LaunchError::DebugUrlNotFound);
173	                }
174	            }
175	            Err(_) if attempts < 20 => {
176	                attempts += 1;
177	                tokio::time::sleep(Duration::from_millis(250)).await;
178	            }
179	            Err(e) => {
180	                return Err(LaunchError::HttpConnectionFailed { url, source: e });
181	            }
182	        }
183	    }
184	}
185	
186	/// Discover the page-level CDP WebSocket URL by polling Chromium's `/json` endpoint.
187	///
188	/// The `/json/version` endpoint returns the browser-level WebSocket URL which only
189	/// supports `Browser.*` and `Target.*` domains. For `Page.*`, `DOM.*`, and `Runtime.*`
190	/// commands, we must connect to a specific page target's WebSocket URL.
191	async fn discover_page_url(port: u16) -> Result<String, LaunchError> {
192	    let url = format!("http://127.0.0.1:{port}/json");
193	    let client = reqwest::Client::new();
194	
195	    let mut attempts = 0;
196	    loop {
197	        match client
198	            .get(&url)
199	            .timeout(Duration::from_secs(5))
200	            .send()
201	            .await
202	        {
203	            Ok(resp) => {
204	                if resp.status().is_success() {
205	                    let targets: Vec<serde_json::Value> = resp.json().await?;
206	                    // Find the first "page" type target (not "background_page", "worker", etc.)
207	                    for target in &targets {
208	                        let target_type = target["type"].as_str().unwrap_or("");
209	                        if target_type == "page" {
210	                            if let Some(page_url) =
211	                                target["webSocketDebuggerUrl"].as_str()
212	                            {
213	                                return Ok(page_url.to_string());
214	                            }
215	                        }
216	                    }
217	                    // If no explicit "page" type, fall back to the first target with a debug URL
218	                    for target in &targets {
219	                        if let Some(page_url) = target["webSocketDebuggerUrl"].as_str() {
220	                            return Ok(page_url.to_string());
221	                        }
222	                    }
223	                    return Err(LaunchError::DebugUrlNotFound);
224	                }
225	            }
226	            Err(_) if attempts < 20 => {
227	                attempts += 1;
228	                tokio::time::sleep(Duration::from_millis(250)).await;
229	            }
230	            Err(e) => {
231	                return Err(LaunchError::HttpConnectionFailed { url, source: e });
232	            }
233	        }
234	    }
235	}
236	
237	/// Locate a Chromium/Chrome executable on the system.
238	async fn find_or_download_chromium() -> Result<PathBuf, LaunchError> {
239	    // Try to find existing Chromium first
240	    if let Some(path) = try_find_chromium() {
241	        return Ok(path);
242	    }
243	
244	    // Auto-download via Playwright
245	    tracing::info!("Chromium not found, downloading automatically via playwright...");
246	    download_chromium().await?;
247	
248	    // Search again after download
249	    if let Some(path) = try_find_chromium() {
250	        tracing::info!(path = %path.display(), "Chromium ready after download");
251	        return Ok(path);
252	    }
253	
254	    Err(LaunchError::ChromiumNotFound {
255	        message: "auto-download also failed. Install Node.js and run: npx playwright install chromium".into(),
256	    })
257	}
258	
259	fn try_find_chromium() -> Option<PathBuf> {
260	    // 0. CHROMIUM_OVERRIDE env var
261	    if let Ok(override_path) = std::env::var("CHROMIUM_OVERRIDE") {
262	        let pb = PathBuf::from(&override_path);
263	        if pb.is_file() {
264	            tracing::info!(path = %pb.display(), "Using CHROMIUM_OVERRIDE");
265	            return Some(pb);
266	        }
267	    }
268	
269	    // 1. Playwright cache
270	    if let Some(pw) = find_playwright_chromium() {
271	        return Some(pw);
272	    }
273	
274	    // 2. PATH
275	    let exe_names: &[&str] = if cfg!(target_os = "windows") {
276	        &["chromium.exe", "chrome.exe"]
277	    } else {
278	        &["chromium", "chromium-browser", "chrome", "google-chrome"]
279	    };
280	    if let Ok(path_var) = std::env::var("PATH") {
281	        for dir in std::env::split_paths(&path_var) {
282	            for name in exe_names {
283	                let candidate = dir.join(name);
284	                if candidate.is_file() {
285	                    return Some(candidate);
286	                }
287	            }
288	        }
289	    }
290	
291	    // 3. macOS bundles
292	    #[cfg(target_os = "macos")]
293	    {
294	        for p in &["/Applications/Chromium.app/Contents/MacOS/Chromium",
295	                    "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome"] {
296	            let pb = PathBuf::from(p);
297	            if pb.is_file() { return Some(pb); }
298	        }
299	    }
300	
301	    // 4. Windows install dirs
302	    #[cfg(target_os = "windows")]
303	    {
304	        let locals = [
305	            std::env::var("LOCALAPPDATA"),
306	            std::env::var("ProgramFiles"),
307	            std::env::var("ProgramFiles(x86)"),
308	        ];
309	        for local_var in locals.iter().flatten() {
310	            for sub in &["Chromium\\Application\\chrome.exe", "Google\\Chrome\\Application\\chrome.exe"] {
311	                let p = PathBuf::from(local_var).join(sub);
312	                if p.is_file() { return Some(p); }
313	            }
314	        }
315	    }
316	
317	    None
318	}
319	
320	async fn download_chromium() -> Result<(), LaunchError> {
321	    let output = tokio::process::Command::new("npx")
322	        .args(["playwright", "install", "chromium"])
323	        .kill_on_drop(true)
324	        .output()
325	        .await
326	        .map_err(|e| LaunchError::DownloadFailed {
327	            message: format!("Failed to run npx: {e}"),
328	        })?;
329	
330	    if !output.status.success() {
331	        let stderr = String::from_utf8_lossy(&output.stderr);
332	        return Err(LaunchError::DownloadFailed {
333	            message: format!("npx playwright install chromium failed: {stderr}"),
334	        });
335	    }
336	
337	    Ok(())
338	}
339	
340	fn find_playwright_chromium() -> Option<PathBuf> {
341	    let cache_root = playwright_cache_root()?;
342	    let exe_subpath: &str = if cfg!(target_os = "windows") {
343	        "chrome-win\\chrome.exe"
344	    } else if cfg!(target_os = "macos") {
345	        "chrome-mac/Chromium.app/Contents/MacOS/Chromium"
346	    } else {
347	        "chrome-linux/chrome"
348	    };
349	
350	    let mut candidates: Vec<PathBuf> = cache_root
351	        .read_dir().ok()?
352	        .filter_map(|entry| {
353	            let entry = entry.ok()?;
354	            let name = entry.file_name();
355	            let name_s = name.to_string_lossy();
356	            if name_s.starts_with("chromium-") || name_s.starts_with("chrome-") {
357	                Some(entry.path())
358	            } else { None }
359	        })
360	        .collect();
361	
362	    candidates.sort_by(|a, b| {
363	        let a_name = a.file_name().map(|n| n.to_string_lossy().to_string()).unwrap_or_default();
364	        let b_name = b.file_name().map(|n| n.to_string_lossy().to_string()).unwrap_or_default();
365	        b_name.cmp(&a_name)
366	    });
367	
368	    for dir in &candidates {
369	        let candidate = dir.join(exe_subpath);
370	        if candidate.is_file() {
371	            tracing::info!(path = %candidate.display(), "Found Chromium in Playwright cache");
372	            return Some(candidate);
373	        }
374	    }
375	    None
376	}
377	
378	fn playwright_cache_root() -> Option<PathBuf> {
379	    #[cfg(target_os = "windows")]
380	    {
381	        Some(PathBuf::from(std::env::var("LOCALAPPDATA").ok()?).join("ms-playwright"))
382	    }
383	    #[cfg(target_os = "macos")]
384	    {
385	        Some(PathBuf::from(std::env::var("HOME").ok()?).join("Library/Caches/ms-playwright"))
386	    }
387	    #[cfg(target_os = "linux")]
388	    {
389	        let home = std::env::var("XDG_CACHE_HOME")
390	            .unwrap_or_else(|_| format!("{}/.cache", std::env::var("HOME").unwrap_or_default()));
391	        Some(PathBuf::from(home).join("ms-playwright"))
392	    }
393	    #[cfg(not(any(target_os = "windows", target_os = "macos", target_os = "linux")))]
394	    { None }
395	}
396	
397	// ── Error type ───────────────────────────────────────────────────────
398	
399	#[derive(Debug, thiserror::Error)]
400	pub enum LaunchError {
401	    #[error("chromium not found — {message}")]
402	    ChromiumNotFound { message: String },
403	
404	    #[error("chromium download failed: {message}")]
405	    DownloadFailed { message: String },
406	
407	    #[error("failed to allocate ephemeral port: {0}")]
408	    PortAllocation(#[from] std::io::Error),
409	
410	    #[error("failed to spawn {exe}: {source}")]
411	    SpawnFailed {
412	        exe: PathBuf,
413	        #[source]
414	        source: std::io::Error,
415	    },
416	
417	    #[error("webSocketDebuggerUrl not found in /json/version response")]
418	    DebugUrlNotFound,
419	
420	    #[error("HTTP request to {url} failed: {source}")]
421	    HttpConnectionFailed {
422	        url: String,
423	        #[source]
424	        source: reqwest::Error,
425	    },
426	
427	    #[error("HTTP response parse error: {0}")]
428	    HttpParse(#[from] reqwest::Error),
429	}
430

