281	    async fn get_distilled_dom(&self, mode: DistillMode) -> Result<DistilledPage, BrowserError> {
282	        let doc_result = self
283	            .connection
284	            .send_command(command::dom_get_document(-1), Duration::from_secs(10))
285	            .await?;
