303	    async fn capture_screenshot(
304	        &self,
305	        format: ImageFormat,
306	        full_page: bool,
307	    ) -> Result<Vec<u8>, BrowserError> {
308	        let (fmt_str, quality) = match format {
309	            ImageFormat::Png => ("png", None),
310	            ImageFormat::Jpeg { quality } => ("jpeg", Some(quality)),
311	        };
312	
313	        let mut params = serde_json::json!({ "format": fmt_str });
314	        if let Some(q) = quality {
315	            params["quality"] = serde_json::json!(q);
316	        }
