48	/// A parsed CDP response.
49	#[derive(Debug, Clone)]
50	pub struct CdpResponse {
51	    pub id: i64,
52	    pub result: Option<Json>,
53	    pub error: Option<CdpError>,
54	}
55	
56	impl CdpResponse {
57	    /// Extract `result` or return the CDP error.
58	    pub fn into_result(self) -> Result<Json, CdpError> {
59	        match self.result {
60	            Some(r) => Ok(r),
61	            None => Err(self.error.unwrap_or_else(|| CdpError {
62	                code: -1,
63	                message: "empty response".into(),
64	            })),
65	        }
66	    }
67	}
68	
69	#[derive(Debug, Clone)]
70	pub struct CdpError {
71	    pub code: i64,
72	    pub message: String,
73	}
74	
75	impl std::fmt::Display for CdpError {
76	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
77	        write!(f, "CDP error {}: {}", self.code, self.message)
78	    }
79	}
80	
81	impl std::error::Error for CdpError {}
82	
83	/// A CDP event (server push, no id field).
84	#[derive(Debug, Clone)]
85	pub struct CdpEvent {
86	    pub method: String,
87	    pub params: Json,
88	}
89	
90	/// Inbound CDP message.
91	#[derive(Debug, Clone)]
92	pub enum CdpMessage {
93	    Response(CdpResponse),
94	    Event(CdpEvent),
95	}
96	
97	/// Parse a raw JSON-RPC message from the WebSocket into a [`CdpMessage`].
98	#[must_use] 
99	pub fn parse_message(text: &str) -> Option<CdpMessage> {
100	    let val: Json = serde_json::from_str(text).ok()?;
101	    let obj = val.as_object()?;
102	
103	    if let Some(id) = obj.get("id").and_then(serde_json::Value::as_i64) {
104	        let result = obj.get("result").cloned();
105	        let error = obj.get("error").map(|e| CdpError {
106	            code: e.get("code").and_then(serde_json::Value::as_i64).unwrap_or(-1),
107	            message: e
108	                .get("message")
109	                .and_then(|v| v.as_str())
110	                .unwrap_or("unknown")
111	                .to_string(),
112	        });
113	        return Some(CdpMessage::Response(CdpResponse { id, result, error }));
114	    }
115	
116	    if let Some(method) = obj.get("method").and_then(|v| v.as_str()) {
117	        let params = obj.get("params").cloned().unwrap_or(Json::Null);
118	        return Some(CdpMessage::Event(CdpEvent {
119	            method: method.to_string(),
120	            params,
121	        }));
122	    }
123	
124	    None
125	}
