310	/// Bounding box from `DOM.getBoxModel`.
311	#[derive(Debug, Clone)]
312	pub struct BoxModel {
313	    pub x: f64,
314	    pub y: f64,
315	    pub width: f64,
316	    pub height: f64,
317	}
318	
319	pub fn parse_box_model(result: &Json) -> Result<BoxModel, CdpError> {
320	    let quad = &result["model"]["content"];
321	    let x1 = quad[0].as_f64().unwrap_or(0.0);
322	    let y1 = quad[1].as_f64().unwrap_or(0.0);
323	    let x2 = quad[4].as_f64().unwrap_or(0.0);
324	    let y2 = quad[5].as_f64().unwrap_or(0.0);
325	    Ok(BoxModel {
326	        x: x1,
327	        y: y1,
328	        width: x2 - x1,
329	        height: y2 - y1,
330	    })
331	}
332	
333	/// Parse `Runtime.evaluate` result.
334	pub fn parse_evaluate_result(result: &Json) -> Result<Json, CdpError> {
335	    if let Some(exception) = result.get("exceptionDetails") {
336	        let text = exception["text"].as_str().unwrap_or("unknown JS exception");
337	        return Err(CdpError {
338	            code: -1,
339	            message: format!("JS exception: {text}"),
340	        });
341	    }
342	    Ok(result["result"]["value"].clone())
343	}
344	
345	/// Decode base64 screenshot data from `Page.captureScreenshot`.
346	pub fn parse_screenshot_result(result: &Json) -> Result<Vec<u8>, CdpError> {
347	    let data = result["data"].as_str().ok_or_else(|| CdpError {
348	        code: -1,
349	        message: "missing data in screenshot response".into(),
350	    })?;
351	    // Use a simple inline base64 decoder — avoids pulling in a crate.
352	    base64_decode(data).ok_or_else(|| CdpError {
353	        code: -1,
354	        message: "base64 decode failed".into(),
355	    })
356	}
357	
358	/// Parse `Page.getFrameTree` — returns the frame tree JSON.
359	#[must_use] 
360	pub fn parse_frame_tree(result: &Json) -> Json {
361	    result["frameTree"].clone()
362	}
