#[must_use] 
pub fn input_dispatch_mouse_event(type_: &str, x: f64, y: f64, button: &str) -> CdpCommand {
    CdpCommand::new(
        "Input.dispatchMouseEvent",
        serde_json::json!({
            "type": type_,
            "x": x,
            "y": y,
            "button": button,
            "clickCount": 1,
        }),
