#[must_use]
pub fn browser_get_version() -> CdpCommand {
    CdpCommand::new("Browser.getVersion", serde_json::json!({}))
}

/// Inject a script that runs before every page's scripts.
/// Used by the stealth engine for anti-detection patches.
#[must_use]
pub fn page_add_script_to_evaluate_on_new_document(source: &str) -> CdpCommand {
    CdpCommand::new(
        "Page.addScriptToEvaluateOnNewDocument",
        serde_json::json!({ "source": source }),
    )
}

// ── Response parsers ─────────────────────────────────────────────────

/// Parse `Page.navigate` → frameId + loaderId.
#[derive(Debug, Clone)]
pub struct NavigationResult {
    pub frame_id: String,
    pub loader_id: String,
}

#[must_use] 
pub fn parse_navigation_result(result: &Json) -> NavigationResult {
    NavigationResult {
        frame_id: result["frameId"].as_str().unwrap_or("").to_string(),
        loader_id: result["loaderId"].as_str().unwrap_or("").to_string(),
    }
}

/// Extract root node id from `DOM.getDocument`.
pub fn parse_dom_node_id(result: &Json) -> Result<i32, CdpError> {
    result["root"]["nodeId"]
        .as_i64()
        .map(|v| v as i32)
        .ok_or_else(|| CdpError {
            code: -1,
            message: "missing root.nodeId in DOM.getDocument response".into(),
        })
}

/// Extract nodeId from `DOM.querySelector`. Returns error on nodeId=0 (not found).
pub fn parse_query_selector_result(result: &Json) -> Result<i32, CdpError> {
    result["nodeId"]
        .as_i64()
        .map(|v| v as i32)
        .filter(|id| *id != 0)
        .ok_or_else(|| CdpError {
            code: -1,
            message: "selector not found (nodeId=0)".into(),
        })
}

/// Extract `outerHTML` from `DOM.getOuterHTML`.
pub fn parse_outer_html(result: &Json) -> Result<String, CdpError> {
    result["outerHTML"]
        .as_str()
        .map(String::from)
        .ok_or_else(|| CdpError {
            code: -1,
            message: "missing outerHTML".into(),
        })
}

/// Bounding box from `DOM.getBoxModel`.
#[derive(Debug, Clone)]
pub struct BoxModel {
    pub x: f64,
    pub y: f64,
    pub width: f64,
    pub height: f64,
}

pub fn parse_box_model(result: &Json) -> Result<BoxModel, CdpError> {
    let quad = &result["model"]["content"];
    let x1 = quad[0].as_f64().unwrap_or(0.0);
    let y1 = quad[1].as_f64().unwrap_or(0.0);
    let x2 = quad[4].as_f64().unwrap_or(0.0);
    let y2 = quad[5].as_f64().unwrap_or(0.0);
    Ok(BoxModel {
        x: x1,
        y: y1,
        width: x2 - x1,
        height: y2 - y1,
    })
}

/// Parse `Runtime.evaluate` result.
pub fn parse_evaluate_result(result: &Json) -> Result<Json, CdpError> {
    if let Some(exception) = result.get("exceptionDetails") {
        let text = exception["text"].as_str().unwrap_or("unknown JS exception");
        return Err(CdpError {
            code: -1,
            message: format!("JS exception: {text}"),
        });
    }
    Ok(result["result"]["value"].clone())
}

/// Decode base64 screenshot data from `Page.captureScreenshot`.
pub fn parse_screenshot_result(result: &Json) -> Result<Vec<u8>, CdpError> {
    let data = result["data"].as_str().ok_or_else(|| CdpError {
        code: -1,
        message: "missing data in screenshot response".into(),
    })?;
    // Use a simple inline base64 decoder — avoids pulling in a crate.
    base64_decode(data).ok_or_else(|| CdpError {
        code: -1,
        message: "base64 decode failed".into(),
    })
}

/// Parse `Page.getFrameTree` — returns the frame tree JSON.
#[must_use] 
pub fn parse_frame_tree(result: &Json) -> Json {
    result["frameTree"].clone()
}

// ── Domain helpers ────────────────────────────────────────────────────

#[derive(Debug, Clone)]
pub struct PageInfo {
    pub url: String,
    pub title: String,
    pub loaded: bool,
}

/// Extract page metadata from a frame tree.
#[must_use] 
pub fn parse_page_info(frame_tree: &Json) -> PageInfo {
    let frame = &frame_tree["frame"];
    PageInfo {
        url: frame["url"].as_str().unwrap_or("").to_string(),
        title: frame["name"].as_str().unwrap_or("").to_string(),
        loaded: true,
    }
}

// ── Simple base64 decoder (no external crate needed) ─────────────────

fn base64_decode(input: &str) -> Option<Vec<u8>> {
    const CHARS: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    let mut buf = Vec::with_capacity(input.len() * 3 / 4);
    let mut accum = 0u32;
    let mut bits = 0u32;

    for b in input.bytes() {
        if b == b'=' {
            break;
        }
        if b.is_ascii_whitespace() {
            continue;
        }
        let idx = CHARS.iter().position(|&c| c == b)? as u32;
        accum = (accum << 6) | idx;
        bits += 6;
        if bits >= 8 {
            bits -= 8;
            buf.push((accum >> bits) as u8);
            accum &= (1 << bits) - 1;
        }
    }
    Some(buf)
}

use std::time::Duration;

use async_trait::async_trait;

use crate::distill::{DistillMode, DistilledPage};
use crate::session::ActionOutcome;

/// The abstract browser interface.
///
/// Every browser engine (Chromium CDP, Servo, Firefox, `WebKit`) implements
/// this trait. The rest of the system never touches a concrete backend —
/// it only calls methods on `dyn BrowserBackend`.
///
/// # Safety
///
/// Implementations must guarantee that calling [`close`](Self::close) (or
/// dropping the backend) terminates the underlying browser process.
/// Zombie processes are a hard bug.
#[async_trait]
pub trait BrowserBackend: Send + Sync {
    /// Navigate to a URL. Returns page metadata after load completes.
    async fn navigate(&self, url: &str, timeout: Duration) -> Result<PageState, BrowserError>;

    /// Get the current page's DOM as a distilled tree.
    async fn get_distilled_dom(&self, mode: DistillMode) -> Result<DistilledPage, BrowserError>;

    /// Capture a screenshot. Returns raw PNG or JPEG bytes.
    async fn capture_screenshot(
        &self,
        format: ImageFormat,
        full_page: bool,
    ) -> Result<Vec<u8>, BrowserError>;

    /// Click an element by CSS selector.
    async fn click(&self, selector: &str) -> Result<ActionOutcome, BrowserError>;

    /// Type text into an element identified by CSS selector.
    async fn type_text(&self, selector: &str, text: &str) -> Result<ActionOutcome, BrowserError>;

    /// Select an option from a `<select>` element.
    async fn select_option(
        &self,
        selector: &str,
        value: &str,
    ) -> Result<ActionOutcome, BrowserError>;

    /// Scroll the page by pixels or to a selector.
    async fn scroll(
        &self,
        pixels: Option<i32>,
        selector: Option<&str>,
    ) -> Result<ActionOutcome, BrowserError>;

    /// Wait for the page to reach a stable loaded state.
    async fn wait_for_load(&self, timeout: Duration) -> Result<PageState, BrowserError>;

    /// Execute arbitrary JavaScript. Returns JSON-serialized result.
    /// Only used for fallback operations; prefer typed CDP commands.
    async fn execute_script(&self, script: &str) -> Result<String, BrowserError>;

    /// Close the browser and clean up all resources.
    async fn close(&self) -> Result<(), BrowserError>;
}

/// Cheap snapshot of what's currently visible in the viewport.
#[derive(Debug, Clone)]
pub struct PageState {
    pub url: String,
    pub title: String,
    pub loaded: bool,
    pub dom_node_count: u64,
    pub visible_text: Vec<String>,
    pub timestamp: chrono::DateTime<chrono::Utc>,
}

/// Screenshot output format.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ImageFormat {
    Png,
    Jpeg { quality: u8 },
}

/// Errors that can bubble up from any browser backend.
#[derive(Debug, thiserror::Error)]
pub enum BrowserError {
    #[error("navigation timeout after {0:?}")]
    NavigationTimeout(Duration),

    #[error("selector not found: {0}")]
    SelectorNotFound(String),

    #[error("element not interactable: {0}")]
    NotInteractable(String),

    #[error("CDP protocol error: {0}")]
    CdpProtocol(String),

    #[error("browser process died unexpectedly")]
    BrowserCrashed,

    #[error("browser closed")]
    BrowserClosed,

    #[error("connection lost: {0}")]
    ConnectionLost(String),

    #[error("internal error: {0}")]
    Internal(#[from] anyhow::Error),
}

